import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RiskCategory {
  VEHICLES = 'Vehículos y Maquinaria',
  PPE = 'Equipo de Protección Personal',
  ENVIRONMENTAL = 'Riesgos Ambientales',
  GENERAL = 'Riesgos Generales'
}

export enum VehicleType {
  TRUCK = 'Camión de Extracción (CAEX)',
  PICKUP = 'Camioneta',
  FORKLIFT = 'Grúa Horquilla',
  EXCAVATOR = 'Excavadora'
}

export const BRANDS: Record<string, string[]> = {
  [VehicleType.TRUCK]: ['Komatsu', 'Caterpillar', 'Thies'],
  [VehicleType.PICKUP]: ['Toyota Hilux', 'Mitsubishi Katana', 'Nissan Navara'],
  [VehicleType.FORKLIFT]: ['Linde', 'Toyota', 'Hyster'],
  [VehicleType.EXCAVATOR]: ['Komatsu', 'CAT', 'Hitachi']
};

export interface SignData {
  title: string;
  category: RiskCategory;
  vehicleType?: VehicleType;
  brand?: string;
  description: string;
  pictogramUrl?: string;
}

import { GoogleGenAI } from "@google/genai";

export const generatePictogram = async (prompt: string): Promise<string | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    // We use gemini-2.5-flash-image for high-quality, fast pictogram generation
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `Create a professional, minimalist black silhouette pictogram for a mining safety sign. 
                   Subject: ${prompt}. 
                   Style: Solid black shape, high contrast, clean edges, flat design, no background (must be on white background), no shading, ISO safety standard style.`
          }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating pictogram:", error);
    return null;
  }
};

