import React, { useState, useEffect } from 'react';
import { RiskCategory, VehicleType, BRANDS, SignData } from './types';
import { generatePictogram } from './services/geminiService';
import Header from './components/Header';
import SignPreview from './components/SignPreview';

const App: React.FC = () => {
  const [signData, setSignData] = useState<SignData>({
    title: 'PELIGRO',
    category: RiskCategory.VEHICLES,
    vehicleType: VehicleType.TRUCK,
    brand: 'Komatsu',
    description: 'TRÁNSITO DE EQUIPOS PESADOS'
  });

  const [isLoading, setIsLoading] = useState(false);

  const handleUpdate = (updates: Partial<SignData>) => {
    setSignData(prev => ({ ...prev, ...updates }));
  };

  const handleGenerate = async () => {
    setIsLoading(true);
    let prompt = '';

    if (signData.category === RiskCategory.VEHICLES) {
      prompt = `${signData.vehicleType} ${signData.brand ? `brand ${signData.brand}` : ''}`;
    } else {
      prompt = signData.description;
    }

    const url = await generatePictogram(prompt);
    if (url) {
      handleUpdate({ pictogramUrl: url });
    }
    setIsLoading(false);
  };

  // Auto-generate on first load
  useEffect(() => {
    handleGenerate();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="min-h-screen bg-slate-50">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8 md:py-12">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">

          {/* Controls Column */}
          <div className="space-y-8 bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div>
              <h2 className="text-xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                <span className="bg-slate-900 text-white p-1 rounded">01</span>
                Configuración del Letrero
              </h2>

              <div className="space-y-6">
                {/* Text Title */}
                <div>
                  <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Título de Advertencia</label>
                  <select 
                    value={signData.title}
                    onChange={(e) => handleUpdate({ title: e.target.value })}
                    className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none transition-all font-semibold"
                  >
                    <option value="PELIGRO">PELIGRO (Riesgo Crítico)</option>
                    <option value="ADVERTENCIA">ADVERTENCIA (Moderado)</option>
                    <option value="PRECAUCIÓN">PRECAUCIÓN (Bajo)</option>
                    <option value="ATENCIÓN">ATENCIÓN (Informativo)</option>
                  </select>
                </div>

                {/* Category Selection */}
                <div>
                  <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Categoría de Riesgo</label>
                  <div className="grid grid-cols-2 gap-3">
                    {Object.values(RiskCategory).map((cat) => (
                      <button
                        key={cat}
                        onClick={() => handleUpdate({ category: cat, vehicleType: cat === RiskCategory.VEHICLES ? VehicleType.TRUCK : undefined })}
                        className={`px-4 py-3 rounded-lg font-bold text-sm transition-all border ${
                          signData.category === cat 
                            ? 'bg-slate-900 text-white border-slate-900' 
                            : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
                        }`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Vehicle Specific Controls */}
                {signData.category === RiskCategory.VEHICLES && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-4 duration-300">
                    <div>
                      <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Tipo de Vehículo / Maquinaria</label>
                      <select 
                        value={signData.vehicleType}
                        onChange={(e) => handleUpdate({ vehicleType: e.target.value as VehicleType, brand: BRANDS[e.target.value][0] })}
                        className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none"
                      >
                        {Object.values(VehicleType).map(type => (
                          <option key={type} value={type}>{type}</option>
                        ))}
                      </select>
                    </div>

                    {signData.vehicleType && BRANDS[signData.vehicleType] && (
                      <div>
                        <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Marca / Modelo Específico</label>
                        <select 
                          value={signData.brand}
                          onChange={(e) => handleUpdate({ brand: e.target.value })}
                          className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none"
                        >
                          {BRANDS[signData.vehicleType].map(brand => (
                            <option key={brand} value={brand}>{brand}</option>
                          ))}
                        </select>
                      </div>
                    )}
                  </div>
                )}

                {/* Description Input */}
                <div>
                  <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Mensaje Inferior (Descripción)</label>
                  <textarea 
                    value={signData.description}
                    onChange={(e) => handleUpdate({ description: e.target.value.toUpperCase() })}
                    placeholder="Ej: ÁREA DE CARGA Y DESCARGA"
                    className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none h-24 font-bold uppercase"
                  />
                  <p className="text-xs text-slate-400 mt-2 italic">Se recomienda usar frases cortas y claras para mejor visibilidad.</p>
                </div>

                <button 
                  onClick={handleGenerate}
                  disabled={isLoading}
                  className="w-full bg-yellow-400 text-black font-black py-4 rounded-xl shadow-lg hover:bg-yellow-500 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3 text-lg uppercase tracking-tight"
                >
                  {isLoading ? (
                    <>
                      <div className="animate-spin h-6 w-6 border-b-2 border-black rounded-full"></div>
                      PROCESANDO...
                    </>
                  ) : (
                    <>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                      GENERAR PICTOGRAMA IA
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>

          {/* Preview Column */}
          <div className="print:m-0">
            <SignPreview data={signData} isLoading={isLoading} />
          </div>

        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-12">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-slate-500 text-sm font-medium">
            Desarrollado para la Industria Minera de Chile. 
            Este generador utiliza modelos de IA de última generación para diseño técnico.
          </p>
          <div className="mt-4 flex justify-center gap-6">
            <div className="flex items-center gap-2 text-slate-400 grayscale opacity-50">
              <span className="text-[10px] font-bold border border-slate-300 px-1 rounded">ISO 7010</span>
              <span className="text-[10px] font-bold border border-slate-300 px-1 rounded">NCh 1411</span>
              <span className="text-[10px] font-bold border border-slate-300 px-1 rounded">OSHA</span>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

