}

import React, { useState, useEffect } from 'react';
import { RiskCategory, VehicleType, ViewType, BRANDS, SignData } from './types';
import { generatePictogram } from './services/geminiService';
import Header from './components/Header';
import SignPreview from './components/SignPreview';

const App: React.FC = () => {
  const [signData, setSignData] = useState<SignData>({
    title: 'PELIGRO',
    category: RiskCategory.VEHICLES,
    vehicleType: VehicleType.TRUCK,
    brand: 'Komatsu',
    viewType: ViewType.LATERAL,
    description: 'TRÁNSITO DE EQUIPOS PESADOS'
  });

  const [isLoading, setIsLoading] = useState(false);

  const handleUpdate = (updates: Partial<SignData>) => {
    setSignData(prev => ({ ...prev, ...updates }));
  };

  const handleGenerate = async () => {
    setIsLoading(true);
    let prompt = '';

    const viewDescription = signData.viewType === ViewType.FRONTAL ? 'front view' : 'side profile view';

    if (signData.category === RiskCategory.VEHICLES) {
      prompt = `${signData.vehicleType} (${signData.brand}), ${viewDescription}`;
    } else {
      prompt = `${signData.description}, ${viewDescription}`;
    }

    const url = await generatePictogram(prompt);
    if (url) {
      handleUpdate({ pictogramUrl: url });
    }
    setIsLoading(false);
  };

  // Auto-generate on first load
  useEffect(() => {
    handleGenerate();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="min-h-screen bg-slate-50">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8 md:py-12">
