                <span className="bg-slate-900 text-white p-1 rounded">01</span>
                Configuración del Letrero
              </h2>

              <div className="space-y-6">
                {/* Text Title */}
                <div>
                  <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Título de Advertencia</label>
                  <select 
                    value={signData.title}
                    onChange={(e) => handleUpdate({ title: e.target.value })}
                    className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none transition-all font-semibold"
                  >
                    <option value="PELIGRO">PELIGRO (Riesgo Crítico)</option>
                    <option value="ADVERTENCIA">ADVERTENCIA (Moderado)</option>
                    <option value="PRECAUCIÓN">PRECAUCIÓN (Bajo)</option>
                    <option value="ATENCIÓN">ATENCIÓN (Informativo)</option>
                  </select>
                </div>

                {/* Category Selection */}
                <div>
                  <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Categoría de Riesgo</label>
                  <div className="grid grid-cols-2 gap-3">
                    {Object.values(RiskCategory).map((cat) => (
                      <button
                        key={cat}
                        onClick={() => handleUpdate({ category: cat, vehicleType: cat === RiskCategory.VEHICLES ? VehicleType.TRUCK : undefined })}
                        className={`px-4 py-3 rounded-lg font-bold text-sm transition-all border ${
                          signData.category === cat 
                            ? 'bg-slate-900 text-white border-slate-900' 
                            : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
                        }`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Vehicle Specific Controls */}
                {signData.category === RiskCategory.VEHICLES && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-4 duration-300">
                    <div>
                      <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Tipo de Vehículo / Maquinaria</label>
                      <select 
                        value={signData.vehicleType}
                        onChange={(e) => handleUpdate({ vehicleType: e.target.value as VehicleType, brand: BRANDS[e.target.value][0] })}
                        className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none"
                      >
                        {Object.values(VehicleType).map(type => (
                          <option key={type} value={type}>{type}</option>
