                          className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none"
                        >
                          {BRANDS[signData.vehicleType].map(brand => (
                            <option key={brand} value={brand}>{brand}</option>
                          ))}
                        </select>
                      </div>
                    )}

                    <div>
                      <label className="block text-sm font-bold text-slate-700 uppercase mb-2">Perspectiva del Dibujo</label>
                      <div className="grid grid-cols-2 gap-3">
                        {Object.values(ViewType).map((view) => (
                          <button
                            key={view}
