import { GoogleGenAI } from "@google/genai";

export const generatePictogram = async (prompt: string): Promise<string | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `High-contrast industrial safety symbol: ${prompt}. 
                   STYLE: Minimalist flat black silhouette icon.
                   BACKGROUND: Pure solid white background (#FFFFFF).
                   REQUIREMENTS: 
                   - No text, labels, or characters.
                   - Sharp thick black outlines.
                   - No shadows, no gradients, no grey colors.
                   - Perfectly centered object.
                   - ISO 7010 compliance style.`
          }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating pictogram:", error);
    return null;
  }
};

