                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Category Selection */}
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Categoría</label>
                    <select
                      value={signData.category}
                      onChange={(e) => handleCategoryChange(e.target.value as RiskCategory)}
                      className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none font-bold text-black"
                    >
                      {Object.values(RiskCategory).map((cat) => (
                        <option key={cat} value={cat}>{cat}</option>
                      ))}
                    </select>
                  </div>

                  {/* Sub-Risk Selection */}
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Riesgo Específico (DT Chile)</label>
                    <select
                      value={signData.subRisk}
                      onChange={(e) => handleUpdate({ subRisk: e.target.value, description: e.target.value.toUpperCase() })}
                      className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none font-bold text-black"
                    >
                      {SUB_RISKS[signData.category].map((risk) => (
                        <option key={risk} value={risk}>{risk}</option>
                      ))}
                    </select>
                  </div>
                </div>

                {/* Dinamyc Detail Selection */}
                <div className="p-4 bg-slate-50 border border-slate-200 rounded-xl space-y-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">{getDetailLabel()}</label>
                    <select 
                      value={signData.elementDetail}
                      onChange={(e) => handleUpdate({ 
                        elementDetail: e.target.value,
                        description: `${signData.subRisk.toUpperCase()}: ${e.target.value.toUpperCase()}`
                      })}
                      className="w-full bg-white border border-slate-300 rounded-lg px-4 py-3 text-black font-bold shadow-sm"
                    >
                      {RISK_ELEMENTS[signData.category].map(item => (
                        <option key={item} value={item}>{item}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Orientación de la Silueta</label>
                  <div className="grid grid-cols-2 gap-3">
                    {Object.values(ViewType).map((view) => (
                      <button
                        key={view}
                        onClick={() => handleUpdate({ viewType: view })}
                        className={`px-4 py-3 rounded-lg font-bold text-sm transition-all border ${
                          signData.viewType === view 
                            ? 'bg-slate-900 text-white border-slate-900' 
                            : 'bg-white text-black border-slate-200 hover:border-slate-400 shadow-sm'
                        }`}
                      >
                        {view}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Description Input */}
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-wider">Texto del Letrero</label>
                  <textarea 
                    value={signData.description}
                    onChange={(e) => handleUpdate({ description: e.target.value.toUpperCase() })}
                    className="w-full bg-slate-50 border border-slate-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-yellow-500 outline-none h-24 font-black text-black text-xl leading-tight"
                  />
                </div>

                <button 
                  onClick={handleGenerate}
                  disabled={isLoading}
                  className="w-full bg-yellow-400 text-black font-black py-5 rounded-xl shadow-lg hover:bg-yellow-500 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3 text-lg uppercase"
                >
                  {isLoading ? (
                    <>
                      <div className="animate-spin h-6 w-6 border-b-2 border-black rounded-full"></div>
                      IA DIBUJANDO...
                    </>
                  ) : (
                    <>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                      ACTUALIZAR PICTOGRAMA
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>

          {/* Preview Column */}
          <div className="print:m-0">
            <SignPreview data={signData} isLoading={isLoading} />
          </div>

        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-12 mt-12">
        <div className="max-w-7xl mx-auto px-4 text-center space-y-4">
          <p className="text-slate-900 font-black tracking-widest text-lg">SIGNA MINERA CHILE</p>
          <p className="text-slate-500 text-sm max-w-2xl mx-auto">
            Herramienta técnica de diseño para prevención de riesgos. 
            Todas las definiciones están basadas en el estudio de la <span className="font-bold">Dirección del Trabajo</span>.
          </p>
          <div className="pt-4 flex justify-center gap-6 grayscale opacity-50">
            <span className="text-[10px] font-bold border border-slate-300 px-2 py-1 rounded">NCh 1411</span>
            <span className="text-[10px] font-bold border border-slate-300 px-2 py-1 rounded">DS 594</span>
            <span className="text-[10px] font-bold border border-slate-300 px-2 py-1 rounded">OSHA ALIGNED</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

